// Callback Page
function CallbackPage({ navigate }) {
  const { exchangeCodeForTokens, fetchUserInfo } = useAuth();
  const [status, setStatus] = useState('processing');
  const [callbackError, setCallbackError] = useState(null);

  useEffect(() => {
    const handleCallback = async () => {
      const params = new URLSearchParams(window.location.search);
      const code = params.get('code');
      const state = params.get('state');
      const error = params.get('error');
      const errorDescription = params.get('error_description');

      if (error) {
        setCallbackError(errorDescription || error);
        setStatus('error');
        return;
      }

      if (!code) {
        setCallbackError('No authorization code received');
        setStatus('error');
        return;
      }

      try {
        setStatus('exchanging');
        await exchangeCodeForTokens(code, state);

        setStatus('fetching_user');
        await fetchUserInfo();

        setStatus('success');

        // Clean up URL
        window.history.replaceState({}, '', '/');
        setTimeout(() => navigate('/'), 1000);
      } catch (err) {
        setCallbackError(err.message);
        setStatus('error');
      }
    };

    handleCallback();
  }, [exchangeCodeForTokens, fetchUserInfo, navigate]);

  if (status === 'error') {
    return React.createElement(
      'div',
      { style: styles.container },
      React.createElement(
        'div',
        { style: { ...styles.card, textAlign: 'center', marginTop: '40px' } },
        React.createElement('div', { style: { fontSize: '48px', marginBottom: '16px' } }, '❌'),
        React.createElement('h2', { style: { color: '#dc3545' } }, 'Authentication Failed'),
        React.createElement('div', { style: styles.errorBox }, callbackError),
        React.createElement(
          'button',
          {
            style: styles.button,
            onClick: () => navigate('/'),
          },
          'Try Again'
        )
      )
    );
  }

  if (status === 'success') {
    return React.createElement(
      'div',
      { style: styles.container },
      React.createElement(
        'div',
        { style: { ...styles.card, textAlign: 'center', marginTop: '40px' } },
        React.createElement('div', { style: { fontSize: '48px', marginBottom: '16px' } }, '✅'),
        React.createElement('h2', { style: { color: '#155724' } }, 'Success!'),
        React.createElement(
          'p',
          { style: { color: '#666' } },
          'You have been authenticated. Redirecting...'
        )
      )
    );
  }

  const messages = {
    processing: 'Processing authentication...',
    exchanging: 'Exchanging authorization code for tokens...',
    fetching_user: 'Fetching user information...',
  };

  return React.createElement(LoadingSpinner, { message: messages[status] || 'Please wait...' });
}

